import java.io.*;
import java.nio.file.*;
import java.util.*;

public class minigit {
    private static final String MINIGIT_DIR = ".minigit";
    private static final String INDEX_FILE = MINIGIT_DIR + "/index";
    private static final String OBJECTS_DIR = MINIGIT_DIR + "/objects";

    public static void main(String[] args) throws IOException {
        if (args.length == 0) {
            exit("No command provided");
        }

        String cmd = args[0];
        switch (cmd) {
            case "init":
                init();
                break;
            case "add":
                if (args.length < 2) exit("No file specified");
                add(args[1]);
                break;
            case "commit":
                if (args.length < 2) exit("No message specified");
                commit(args[1]);
                break;
            case "log":
                log();
                break;
            default:
                exit("Unknown command: " + cmd);
        }
    }

    private static void init() throws IOException {
        File dir = new File(MINIGIT_DIR);
        if (dir.exists()) {
            exit("Already initialized");
        }
        dir.mkdir();
        new File(OBJECTS_DIR).mkdir();
        Files.write(Paths.get(INDEX_FILE), new byte[0]);
        System.out.println("Initialized minigit");
    }

    private static void add(String filename) throws IOException {
        checkInit();
        File f = new File(filename);
        if (!f.exists()) exit("File not found");
        String content = Files.readString(f.toPath());
        String hash = sha1(content);
        Path objPath = Paths.get(OBJECTS_DIR, hash);
        Files.writeString(objPath, content);
        List<String> index = Files.readAllLines(Paths.get(INDEX_FILE));
        index.removeIf(line -> line.startsWith(filename + " "));
        index.add(filename + " " + hash);
        Files.write(Paths.get(INDEX_FILE), String.join("\n", index).getBytes());
    }

    private static void commit(String msg) throws IOException {
        checkInit();
        List<String> index = Files.readAllLines(Paths.get(INDEX_FILE));
        if (index.isEmpty()) exit("No files staged");
        StringBuilder sb = new StringBuilder();
        sb.append("commit ").append(msg).append("\n");
        for (String line : index) {
            String[] parts = line.split(" ", 2);
            sb.append(parts[1]).append(" ").append(parts[0]).append("\n");
        }
        String content = sb.toString();
        String hash = sha1(content);
        Path objPath = Paths.get(OBJECTS_DIR, hash);
        Files.writeString(objPath, content);
        System.out.println("Committed " + hash);
    }

    private static void log() throws IOException {
        checkInit();
        File objects = new File(OBJECTS_DIR);
        String[] files = objects.list();
        if (files == null || files.length == 0) {
            exit("No commits found");
        }
        List<String> commits = new ArrayList<>();
        for (String f : files) {
            String content = Files.readString(Paths.get(OBJECTS_DIR, f));
            if (content.startsWith("commit ")) {
                commits.add(f);
            }
        }
        if (commits.isEmpty()) exit("No commits found");
        for (String c : commits) {
            String content = Files.readString(Paths.get(OBJECTS_DIR, c));
            String msg = content.split("\n", 2)[0].substring(7);
            System.out.println(c + " " + msg);
        }
    }

    private static void checkInit() {
        if (!new File(MINIGIT_DIR).exists()) {
            exit("Not initialized");
        }
    }

    private static String sha1(String input) {
        try {
            java.security.MessageDigest md = java.security.MessageDigest.getInstance("SHA-1");
            byte[] messageDigest = md.digest(input.getBytes());
            StringBuilder sb = new StringBuilder();
            for (byte b : messageDigest) {
                sb.append(String.format("%02x", b));
            }
            return sb.toString();
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private static void exit(String msg) {
        System.err.println(msg);
        System.exit(1);
    }
}
